import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function detectRugpullPatterns(chainName, tokenAddress) {
  const [events, approvals] = await Promise.all([
    client.BaseService.getLogEventsByAddress(chainName, tokenAddress),
    client.SecurityService.getApprovals(chainName, tokenAddress),
  ]);
  const lpRemovals = (events.data?.items ?? []).filter(
    e => e.decoded?.name === "RemoveLiquidity" || e.decoded?.name === "Burn"
  );
  const highRiskApprovals = (approvals.data?.items ?? []).filter(a => (a.risk_score ?? 0) > 80);
  const rugScore = lpRemovals.length * 20 + highRiskApprovals.length * 15;
  return { tokenAddress, rugScore: Math.min(100, rugScore), lpRemovals: lpRemovals.length };
}
